INSERT INTO `activity_prices` (`id`, `code`, `title`, `unit`, `unit_price`, `created_at`, `updated_at`) VALUES (1,'911377-1','ЩҶШөШЁ ЫҢШ§ ШӘШ№ЩҲЫҢШ¶ Щ…ЩҲШҜЩ… ШҜШұ ШҜШ§Ш®Щ„ ШӘШ§ШЁЩ„ЩҲ ШӘШ¬ЩҮЫҢШІШ§ШӘ Ш§ШӘЩҲЩ…Ш§ШіЫҢЩҲЩҶЫҢ ШЁЩҮ ЩҮЩ…ШұШ§ЩҮ ШіЫҢЩ…вҖҢЪ©ШҙЫҢвҖҢЩҮШ§ЫҢ Щ„Ш§ШІЩ…','Щ…ЩҲШұШҜ',1800000,'2026-04-23 20:47:27','2026-04-23 20:47:27'),(2,'911378-1','ЩҶШөШЁ ЫҢШ§ ШӘШ№ЩҲЫҢШ¶ ЩҫЩҶЩ„ Ъ©ЩҶШӘШұЩ„ (RTU) ШҜШұ ШҜШ§Ш®Щ„ ШӘШ§ШЁЩ„ЩҲ ШӘШ¬ЩҮЫҢШІШ§ШӘ Ш§ШӘЩҲЩ…Ш§ШіЫҢЩҲЩҶЫҢ ШЁЩҮ ЩҮЩ…ШұШ§ЩҮ ШіЫҢЩ…вҖҢЪ©ШҙЫҢвҖҢЩҮШ§ЫҢ Щ„Ш§ШІЩ…','Щ…ЩҲШұШҜ',1800000,'2026-04-23 20:47:27','2026-04-23 20:47:27'),(3,'911379-1','ЩҶШөШЁ ЫҢШ§ ШӘШ№ЩҲЫҢШ¶ ШЁШ§Ш·ШұЫҢ ШҜШұ ШҜШ§Ш®Щ„ ШӘШ¬ЩҮЫҢШІШ§ШӘ Ш§ШӘЩҲЩ…Ш§ШіЫҢЩҲЩҶЫҢ ШЁЩҮ ЩҮЩ…ШұШ§ЩҮ ШіЫҢЩ…вҖҢЪ©ШҙЫҢвҖҢЩҮШ§ЫҢ Щ„Ш§ШІЩ…','Щ…Ш¬Щ…ЩҲШ№ЩҮ',1500000,'2026-04-23 20:47:27','2026-04-23 20:47:27'),(4,'911380-1','ЩҶШөШЁ ЫҢШ§ ШӘШ№ЩҲЫҢШ¶ ЩҫШ§ЩҲШұ ШӘШәШ°ЫҢЩҮ ШҜШұ ШҜШ§Ш®Щ„ ШӘШ§ШЁЩ„ЩҲ ШӘШ¬ЩҮЫҢШІШ§ШӘ Ш§ШӘЩҲЩ…Ш§ШіЫҢЩҲЩҶЫҢ ШЁЩҮ ЩҮЩ…ШұШ§ЩҮ ШіЫҢЩ…вҖҢЪ©ШҙЫҢвҖҢЩҮШ§ЫҢ Щ„Ш§ШІЩ…','ШҜШіШӘЪҜШ§ЩҮ',1800000,'2026-04-23 20:47:27','2026-04-23 20:47:27'),(5,'911381-1','ЩҶШөШЁ ЫҢШ§ ШӘШ№ЩҲЫҢШ¶ ЩҒЫҢЩҲШІ Щ…ЫҢЩҶЫҢШ§ШӘЩҲШұЫҢ ШҜШұ ШҜШ§Ш®Щ„ ШӘШ§ШЁЩ„ЩҲ ШӘШ¬ЩҮЫҢШІШ§ШӘ Ш§ШӘЩҲЩ…Ш§ШіЫҢЩҲЩҶЫҢ ШЁЩҮ ЩҮЩ…ШұШ§ЩҮ ШіЫҢЩ…вҖҢЪ©ШҙЫҢвҖҢЩҮШ§ЫҢ Щ„Ш§ШІЩ…','Щ…ЩҲШұШҜ',700000,'2026-04-23 20:47:27','2026-04-23 20:47:27'),(6,'911382-1','ЩҶШөШЁ ЫҢШ§ ШӘШ№ЩҲЫҢШ¶ ЩҒЫҢЩҲШІ ЩҒШҙЩҶЪҜЫҢ ШҜШұ ШҜШ§Ш®Щ„ ШӘШ§ШЁЩ„ЩҲ ШӘШ¬ЩҮЫҢШІШ§ШӘ Ш§ШӘЩҲЩ…Ш§ШіЫҢЩҲЩҶЫҢ ШЁЩҮ ЩҮЩ…ШұШ§ЩҮ ШіЫҢЩ…вҖҢЪ©ШҙЫҢвҖҢЩҮШ§ЫҢ Щ„Ш§ШІЩ…','Щ…ЩҲШұШҜ',500000,'2026-04-23 20:47:27','2026-04-23 20:47:27'),(7,'911383-1','ЩҶШөШЁШҢ Ш§ШөЩ„Ш§Шӯ ЩҲ ЫҢШ§ ШӘШ№ЩҲЫҢШ¶ ШіЫҢЩ…вҖҢЪ©ШҙЫҢ ЩҲ Ш§ШӘШөШ§Щ„Ш§ШӘ ШҜШұ ШҜШ§Ш®Щ„ ШӘШ§ШЁЩ„ЩҲ ШӘШ¬ЩҮЫҢШІШ§ШӘ Ш§ШӘЩҲЩ…Ш§ШіЫҢЩҲЩҶЫҢ ШЁШҜЩҲЩҶ ЩҶШөШЁ ШӘШ¬ЩҮЫҢШІ','Щ…ЩҲШұШҜ',1200000,'2026-04-23 20:47:27','2026-04-23 20:47:27'),(8,'911384-1','ЩҶШөШЁ ЫҢШ§ ШӘШ№ЩҲЫҢШ¶ ШіЫҢЩ… Ъ©Ш§ШұШӘ Щ…ЩҲШҜЩ… ШҜШұ ШҜШ§Ш®Щ„ ШӘШ§ШЁЩ„ЩҲ ШӘШ¬ЩҮЫҢШІШ§ШӘ Ш§ШӘЩҲЩ…Ш§ШіЫҢЩҲЩҶЫҢ ШЁЩҮ ЩҮЩ…ШұШ§ЩҮ ШӘШіШӘ Ш§ШұШӘШЁШ§Ш·','Щ…ЩҲШұШҜ',1200000,'2026-04-23 20:47:27','2026-04-23 20:47:27'),(9,'911385-1','Ш§ЩҶШ¬Ш§Щ… ШӘЩҶШё