  `simcard_number` varchar(20) DEFAULT NULL COMMENT 'в•Әв”Өв”ҳлҝҜВҪв•ӘлҝҜВҪв•ӘлҝҜв–Ҫв”ҳлҝҜВҪ в•Әв”ӮлҝҜв–ҪлҝҜВҪв”ҳлҝҜВҪлҝҜОҪлҝҜВҪлҝҜВҪв”ҢвҢҗв•ӘлҝҜВҪв•ӘлҝҜв–Ҫв•ӘлҝҜВҪ',
  `simcard_ip` varchar(45) DEFAULT NULL COMMENT 'в•ӘлҝҜВҪлҝҜв–ҪлҝҜВҪлҝҜОҪлҝҜВҪлҝҜВҪв”ҳв•ӣлҝҜв–ҪлҝҜВҪ в•Әв”ӮлҝҜв–ҪлҝҜВҪв”ҳлҝҜВҪлҝҜОҪлҝҜВҪлҝҜВҪв”ҢвҢҗв•ӘлҝҜВҪв•ӘлҝҜв–Ҫв•ӘлҝҜВҪ',
  `antenna_status` varchar(50) DEFAULT NULL COMMENT 'в”ҳлҝҜВҪв•Әв•ўв•Әв•ЈлҝҜв–ҪлҝҜВҪв•ӘлҝҜВҪ в”ҳлҝҜВҪв•Әв•Ўв•ӘлҝҜВҪ в•ӘлҝҜВҪв”ҳлҝҜВҪв•ӘлҝҜВҪв”ҳлҝҜВҪ',
  `signal_status` varchar(20) DEFAULT NULL COMMENT 'в”ҳлҝҜВҪв•Әв•ўв•Әв•ЈлҝҜв–ҪлҝҜВҪв•ӘлҝҜВҪ в•Әв”ӮлҝҜв–ҪлҝҜВҪв”ҢлҝҜВҪв”ҳлҝҜВҪв•ӘлҝҜВҪв”ҳлҝҜВҪ (в•ӘлҝҜВҪв”ҳлҝҜВҪв•ӘлҝҜВҪ/в•Әв•ўв•Әв•ЈлҝҜв–ҪлҝҜВҪв”ҳлҝҜВҪ)',
  `modem_power` varchar(20) DEFAULT NULL COMMENT 'в•ӘлҝҜВҪв•Әв•‘в•ӘлҝҜв–ҪлҝҜв–ҪлҝҜВҪв”ҳлҝҜВҪ в”ҳлҝҜВҪв”ҳлҝҜВҪв•ӘлҝҜВҪв”ҳлҝҜВҪ (в”ҳв•ӣв”ҳлҝҜВҪв”ҳлҝҜВҪ/в•ӘлҝҜВҪв•ӘлҝҜВҪв•ӘлҝҜВҪв•ӘлҝҜв–ҪлҝҜв–ҪлҝҜВҪ)',
  `reset_possible` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'в”ҳлҝҜВҪв•ӘлҝҜВҪв•ӘлҝҜВҪв”ҳлҝҜВҪлҝҜв–ҪлҝҜВҪв•ӘлҝҜВҪ в•ӘлҝҜв–ҪлҝҜв–ҪлҝҜВҪв•Әв”Ӯв•ӘлҝҜВҪ',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `equipment_communications_main_equipment_id_index` (`main_equipment_id`),
  KEY `equipment_communications_simcard_number_index` (`simcard_number`),
  CONSTRAINT `equipment_communications_main_equipment_id_foreign` FOREIGN KEY (`main_equipment_id`) REFERENCES `main_equipments` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=336 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
