UNLOCK TABLES;
DROP TABLE IF EXISTS `equipment_consumables`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `equipment_consumables` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `main_equipment_id` bigint(20) unsigned NOT NULL,
  `name` varchar(200) NOT NULL COMMENT 'в”ҳлҝҜВҪв•ӘлҝҜВҪв”ҳлҝҜВҪ в”ҳлҝҜВҪв”ҳлҝҜВҪв”ҳлҝҜВҪ в”ҳлҝҜВҪв•Әв•Ўв•ӘлҝҜв–Ҫв”ҳлҝҜВҪлҝҜв–ҪлҝҜВҪ',
  `other_name` varchar(200) DEFAULT NULL COMMENT 'в”ҳлҝҜВҪв•ӘлҝҜВҪв”ҳлҝҜВҪ в•ӘлҝҜВҪлҝҜв–ҪлҝҜВҪв”ҢлҝҜВҪв•ӘлҝҜв–Ҫ (в•ӘлҝҜВҪв•ӘлҝҜв–Ҫв•ӘлҝҜВҪлҝҜв–ҪлҝҜВҪ в•Әв”Ӯв•ӘлҝҜВҪлҝҜв–ҪлҝҜВҪв•ӘлҝҜв–Ҫ в•ӘлҝҜВҪв”ҳлҝҜВҪв”ҳлҝҜВҪв•ӘлҝҜВҪв”ҳлҝҜВҪ)',
  `quantity` int(11) NOT NULL DEFAULT 1 COMMENT 'в•ӘлҝҜВҪв•Әв•Јв•ӘлҝҜВҪв•ӘлҝҜВҪв•ӘлҝҜВҪ',
  `unit` varchar(50) DEFAULT NULL COMMENT 'в”ҳлҝҜВҪв•ӘлҝҜВҪв•ӘлҝҜВҪв•ӘлҝҜВҪ (в•Әв•Јв•ӘлҝҜВҪв•ӘлҝҜВҪв•ӘлҝҜВҪ в”ҳлҝҜВҪв•ӘлҝҜВҪв•ӘлҝҜв–Ҫв•ӘлҝҜВҪ ...)',
  `description` text DEFAULT NULL COMMENT 'в•ӘлҝҜВҪв”ҳлҝҜВҪв•Әв•ўлҝҜв–ҪлҝҜВҪв•ӘлҝҜВҪв•ӘлҝҜВҪв•ӘлҝҜВҪ',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `equipment_consumables_main_equipment_id_index` (`main_equipment_id`),
  KEY `equipment_consumables_name_index` (`name`),
  CONSTRAINT `equipment_consumables_main_equipment_id_foreign` FOREIGN KEY (`main_equipment_id`) REFERENCES `main_equipments` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=240 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

