UNLOCK TABLES;
DROP TABLE IF EXISTS `equipment_feeders`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `equipment_feeders` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `main_equipment_id` bigint(20) unsigned NOT NULL,
  `post` varchar(191) DEFAULT NULL COMMENT 'в”ҳлҝҜВҪв•ӘлҝҜВҪв”ҳлҝҜВҪ в”ҳв•ӣв•Әв”Ӯв•ӘлҝҜВҪ',
  `feeder` varchar(191) DEFAULT NULL COMMENT 'в”ҳлҝҜВҪв•ӘлҝҜВҪв”ҳлҝҜВҪ в”ҳлҝҜВҪлҝҜв–ҪлҝҜВҪв•ӘлҝҜВҪв•ӘлҝҜв–Ҫ',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `equipment_feeders_main_equipment_id_index` (`main_equipment_id`),
  KEY `equipment_feeders_post_index` (`post`),
  KEY `equipment_feeders_feeder_index` (`feeder`),
  CONSTRAINT `equipment_feeders_main_equipment_id_foreign` FOREIGN KEY (`main_equipment_id`) REFERENCES `main_equipments` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=411 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

