UNLOCK TABLES;
DROP TABLE IF EXISTS `equipment_locations`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `equipment_locations` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `main_equipment_id` bigint(20) unsigned NOT NULL,
  `latitude` decimal(10,7) DEFAULT NULL COMMENT 'в•Әв•Јв•ӘлҝҜв–Ҫв•Әв•ў в•ӘлҝҜВҪв•Әв•‘в•ӘлҝҜв–Ҫв•ӘлҝҜВҪв”ҳлҝҜВҪлҝҜв–ҪлҝҜВҪв•ӘлҝҜВҪлҝҜв–ҪлҝҜВҪлҝҜв–ҪлҝҜВҪ',
  `longitude` decimal(10,7) DEFAULT NULL COMMENT 'в•Әв•–в”ҳлҝҜВҪв”ҳлҝҜВҪ в•ӘлҝҜВҪв•Әв•‘в•ӘлҝҜв–Ҫв•ӘлҝҜВҪв”ҳлҝҜВҪлҝҜв–ҪлҝҜВҪв•ӘлҝҜВҪлҝҜв–ҪлҝҜВҪлҝҜв–ҪлҝҜВҪ',
  `address` text DEFAULT NULL COMMENT 'в•ӘлҝҜВҪв•ӘлҝҜВҪв•ӘлҝҜв–Ҫв•Әв”Ӯ в”ҳлҝҜВҪв•Әв•Ўв•ӘлҝҜВҪ',
  `cabinet_initial_height` decimal(5,2) DEFAULT NULL COMMENT 'в•ӘлҝҜВҪв•ӘлҝҜв–Ҫв•ӘлҝҜВҪв”ҳлҝҜВҪв•ӘлҝҜВҪв•Әв•Ј в•ӘлҝҜВҪв”ҳлҝҜВҪв”ҳлҝҜВҪлҝҜв–ҪлҝҜВҪв”ҳлҝҜВҪ в•ӘлҝҜВҪв•ӘлҝҜВҪв•ӘлҝҜВҪв”ҳлҝҜВҪв”ҳлҝҜВҪ (в”ҳлҝҜВҪв•ӘлҝҜВҪв•ӘлҝҜв–Ҫ)',
  `cabinet_final_height` decimal(5,2) DEFAULT NULL COMMENT 'в•ӘлҝҜВҪв•ӘлҝҜв–Ҫв•ӘлҝҜВҪв”ҳлҝҜВҪв•ӘлҝҜВҪв•Әв•Ј в”ҳлҝҜВҪв”ҳлҝҜВҪв•ӘлҝҜВҪлҝҜв–ҪлҝҜВҪлҝҜв–ҪлҝҜВҪ в•ӘлҝҜВҪв•ӘлҝҜВҪв•ӘлҝҜВҪв”ҳлҝҜВҪв”ҳлҝҜВҪ (в”ҳлҝҜВҪв•ӘлҝҜВҪв•ӘлҝҜв–Ҫ)',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `equipment_locations_main_equipment_id_index` (`main_equipment_id`),
  KEY `equipment_locations_latitude_longitude_index` (`latitude`,`longitude`),
  CONSTRAINT `equipment_locations_main_equipment_id_foreign` FOREIGN KEY (`main_equipment_id`) REFERENCES `main_equipments` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=256 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `equipment_locations` WRITE;
