  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `equipment_photos_main_equipment_id_index` (`main_equipment_id`),
  KEY `equipment_photos_scan_code_index` (`scan_code`),
  KEY `equipment_photos_sort_order_index` (`sort_order`),
