CREATE TABLE `inspections` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `user_id` bigint(20) unsigned DEFAULT NULL,
  `contractor_id` bigint(20) unsigned DEFAULT NULL,
  `department_id` bigint(20) unsigned DEFAULT NULL,
  `inspection_date` date DEFAULT NULL,
  `daily_start_time` time DEFAULT NULL,
  `daily_end_time` time DEFAULT NULL,
  `status` enum('draft','completed','archived') NOT NULL DEFAULT 'draft',
  `report_number` varchar(100) DEFAULT NULL,
  `final_status` enum('pending','approved','rejected') DEFAULT NULL,
  `supervisor_notes` text DEFAULT NULL,
  `approved_by` bigint(20) DEFAULT NULL,
  `approved_at` timestamp NULL DEFAULT NULL,
  `total_cost` decimal(15,2) DEFAULT NULL,
  `travel_distance` int(11) DEFAULT 0,
  `travel_cost` decimal(15,2) DEFAULT NULL,
  `signature_path` varchar(500) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `inspections_user_id_foreign` (`user_id`),
  KEY `contractor_id` (`contractor_id`),
  KEY `inspections_department_id_foreign` (`department_id`),
  KEY `inspections_contractor_id_foreign_idx` (`contractor_id`),
  CONSTRAINT `inspections_contractor_id_foreign` FOREIGN KEY (`contractor_id`) REFERENCES `contractors` (`id`) ON DELETE SET NULL,
  CONSTRAINT `inspections_department_id_foreign` FOREIGN KEY (`department_id`) REFERENCES `departments` (`id`) ON DELETE SET NULL,
  CONSTRAINT `inspections_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=160 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `inspections` WRITE;
