CREATE TABLE `main_equipment_types` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `category` enum('main','cell') NOT NULL DEFAULT 'main',
  `code` varchar(50) DEFAULT NULL,
  `description` text DEFAULT NULL,
  `feeder_mode` enum('single','dual') NOT NULL DEFAULT 'single',
  `has_cells` tinyint(1) NOT NULL DEFAULT 0,
  `has_brand` tinyint(1) NOT NULL DEFAULT 0,
  `has_height` tinyint(1) NOT NULL DEFAULT 1,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `main_equipment_types_name_unique` (`name`)
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
